const CACHE_VERSION="lacadev-v1.1.0",CACHE_NAME=`lacadev-cache-${CACHE_VERSION}`,STATIC_ASSETS=["/","/dist/styles/theme.css","/dist/theme.js","/offline.php"];function isStaticAsset(e){const t=new URL(e.url);return[".css",".js",".jpg",".jpeg",".png",".gif",".webp",".svg",".woff",".woff2",".ttf",".eot"].some(e=>t.pathname.endsWith(e))}async function cacheFirst(e){try{const t=await caches.match(e);if(t)return t;const a=await fetch(e);if(a&&200===a.status){(await caches.open(CACHE_NAME)).put(e,a.clone())}return a}catch(e){const t=await caches.match("/offline.php");return t||new Response("Offline — Không có kết nối mạng",{status:503,statusText:"Service Unavailable"})}}async function networkFirst(e){try{const t=await fetch(e);if(t&&200===t.status){(await caches.open(CACHE_NAME)).put(e,t.clone())}return t}catch(t){const a=await caches.match(e);if(a)return a;const s=await caches.match("/offline.php");return s||new Response("Offline — Không có kết nối mạng",{status:503,statusText:"Service Unavailable"})}}self.addEventListener("install",e=>{e.waitUntil(caches.open(CACHE_NAME).then(e=>e.addAll(STATIC_ASSETS.map(e=>new Request(e,{cache:"reload"})))).then(()=>self.skipWaiting()).catch(e=>{}))}),self.addEventListener("activate",e=>{e.waitUntil(caches.keys().then(e=>Promise.all(e.filter(e=>e.startsWith("lacadev-cache-")).filter(e=>e!==CACHE_NAME).map(e=>caches.delete(e)))).then(()=>self.clients.claim()))}),self.addEventListener("fetch",e=>{const{request:t}=e,a=new URL(t.url);a.origin===location.origin&&(a.pathname.includes("/wp-admin")||a.pathname.includes("/wp-login")||a.pathname.includes("admin-ajax.php")||a.pathname.includes("/wp-json/")||"GET"===t.method&&(isStaticAsset(t)?e.respondWith(cacheFirst(t)):e.respondWith(networkFirst(t))))}),self.addEventListener("message",e=>{e.data&&"SKIP_WAITING"===e.data.type&&self.skipWaiting(),e.data&&"CLEAR_CACHE"===e.data.type&&e.waitUntil(caches.delete(CACHE_NAME).then(()=>self.clients.matchAll()).then(e=>{e.forEach(e=>{e.postMessage({type:"CACHE_CLEARED"})})}))});